// ═══════════════════════════════════════════════════════════════════
//  QA DEVOPS — AUDITORIA FULL SCOPE
//  Preencha as constantes abaixo com suas credenciais
//  Sprint-based: janela de 30 dias (sprint inteira)
//  API: this.helpers.httpRequest (NÃO usar fetch)
// ═══════════════════════════════════════════════════════════════════

const GITLAB_TOKEN = 'SEU_GITLAB_TOKEN';
const DISCORD_URL  = 'SEU_DISCORD_WEBHOOK_URL';
const JIRA_DOMAIN  = 'sua-empresa.atlassian.net';
const JIRA_EMAIL   = 'seu@email.com';
const JIRA_TOKEN   = 'SEU_JIRA_TOKEN';
const SENDGRID_KEY = 'SEU_SENDGRID_KEY';
const GL_GROUP     = 'seu-grupo-gitlab';
const JIRA_BOARD   = 1;

const glHeaders   = { 'PRIVATE-TOKEN': GITLAB_TOKEN };
const jiraAuth    = 'Basic ' + Buffer.from(`${JIRA_EMAIL}:${JIRA_TOKEN}`).toString('base64');
const jiraHeaders = { 'Authorization': jiraAuth, 'Accept': 'application/json' };

// ── Sprint X: DD/MM/YYYY até hoje (acumula conforme avança) ─────────
// Início fixo no calendário Fatec SJC 1º sem 2026
const now         = new Date();
const sprintStart = new Date('2025-01-01T00:00:00.000Z') // AJUSTE: data de início da sua sprint;
const sprintEnd   = new Date(now);
sprintEnd.setHours(23, 59, 59, 999);
const sprintDays  = Math.ceil((now - sprintStart) / (1000*60*60*24));
const periodLabel = `Sprint X: DD/MM/YYYY a ${now.toLocaleDateString('pt-BR')} (${sprintDays} dias)`;

// ── Repo principal (commits diretos permitidos, sem MR obrigatório)
const MAIN_REPO_SLUG = 'seu-grupo/seu-repo-principal';

// ── Padrões baseados no documento CI do projeto ────────────────────
// Branch válida: precisa ter tipo (feat/fix/docs/etc) + ID numérico em algum formato
// Exemplos válidos: feat/SCRUM-12, feat[75,76]-descricao, feat-75-descricao
const branchValidPattern = /^(feat|fix|docs|refactor|chore|test|hotfix|release)[\s\-\/\[].*\d+/i;
// Exceções permanentes — nunca geram NC
const branchExceptions   = /^(main|develop|master|HEAD|ReleaseSprint)/i;

// Commit válido: tipo[ID]: msg  OU  tipo[ID,ID]: msg  OU  tipo: msg
// Aceita SCRUM-XX, números simples [72], múltiplos [72,73]
// "docs:" sem ID é válido. "feat:" sem ID é aceito (convenção flexível do projeto)
const commitValidPattern = /^(feat|fix|docs|refactor|style|test|chore)(\[[\w,\s\-]+\])?:/i;
const mergeCommitPattern = /^Merge (branch|remote|pull|tag)/i;
const genericWords       = /^(update|teste|test|aaa|ajuste|commit|wip|temp|tmp|asdf|ok|done|changes|add|remove|clean|cleanup|inicio|começo|begin|arrumando|mudanca|alteracao)$/i;

// Testes: TC-XX-nome.spec.ts OU *.int.spec.ts OU *.int.test.ts
const specFilePattern = /\.(spec|test|int\.spec|int\.test)\.(ts|tsx|js|jsx)$/;
const tcFilePattern   = /^TC-\d{2,3}-[a-zA-Z0-9]+\.(spec|int\.spec)\.(ts|tsx|js|jsx)$/;
const intSpecPattern  = /\.int\.(spec|test)\.(ts|tsx|js|jsx)$/;

// Limiares temporais
const STALE_DAYS     = 30; // branch stale após 30 dias sem atividade
const DOC_WARN_DAYS  = 30; // docs só viram NC após 30 dias sem atualização

// ── Helper: httpRequest via n8n nativo ────────────────────────────
const glGet = async (url) => {
  try {
    const sep = url.includes('?') ? '&' : '?';
    const result = await this.helpers.httpRequest({
      method: 'GET',
      url: url + sep + 'per_page=100',
      headers: glHeaders,
    });
    return Array.isArray(result) ? result : [];
  } catch(e) { return []; }
};

const jiraGet = async (url) => {
  try {
    const r = await this.helpers.httpRequest({
      method: 'GET', url, headers: jiraHeaders,
      returnFullResponse: true, ignoreHttpStatusErrors: true,
    });
    const body = typeof r.body === 'string' ? JSON.parse(r.body) : (r.body ?? r);
    if (body && typeof body === 'object') body.__status = r.statusCode;
    return body || {};
  } catch(e) { return { __error: e.message }; }
};

// ═══════════════════════════════════════════════════════════════════
//  STEP 1 — REPOSITÓRIOS DO GRUPO
// ═══════════════════════════════════════════════════════════════════
let repos = [];
try {
  const raw = await glGet(`https://gitlab.com/api/v4/groups/${GL_GROUP}/projects`);
  repos = raw.map(p => {
    const slug = p.path_with_namespace || '';
    const defaultBranch = p.default_branch || (slug.includes('api-4-sem') ? 'main' : 'develop');
    return { name: p.name, slug, url: p.web_url, defaultBranch };
  });
} catch(e) {}

if (repos.length === 0) {
  repos = [
    { name: 'Principal',  slug: 'seu-grupo/seu-repo-principal',  url: 'https://gitlab.com/the-devs6675810/api-4-sem-tecsus',  defaultBranch: 'main'    },
    { name: 'Backend',    slug: 'the-devs6675810/back-end-tecsus',   url: 'https://gitlab.com/the-devs6675810/back-end-tecsus',   defaultBranch: 'develop' },
    { name: 'Frontend',   slug: 'the-devs6675810/front-end-tecsus',  url: 'https://gitlab.com/the-devs6675810/front-end-tecsus',  defaultBranch: 'develop' },
    { name: 'Datalogger', slug: 'the-devs6675810/datalogger-tecsus', url: 'https://gitlab.com/the-devs6675810/datalogger-tecsus', defaultBranch: 'develop' },
  ];
}

// ═══════════════════════════════════════════════════════════════════
//  STEP 2 — MERGE REQUESTS (últimos 30 dias)
// ═══════════════════════════════════════════════════════════════════
const mrResults = [];
let mrTotal = 0, mrOk = 0;

for (const repo of repos) {
  if (repo.slug === MAIN_REPO_SLUG) continue;
  const enc = encodeURIComponent(repo.slug);
  const mrs = await glGet(`https://gitlab.com/api/v4/projects/${enc}/merge_requests?state=merged&updated_after=${sprintStart.toISOString()}`);

  for (const mr of mrs) {
    let approvers = [];
    try {
      const ad = await this.helpers.httpRequest({ method:'GET', url:`https://gitlab.com/api/v4/projects/${enc}/merge_requests/${mr.iid}/approvals`, headers:glHeaders });
      approvers = ad.approved_by || [];
    } catch(e) {}

    let pipelines = [];
    try {
      const pd = await this.helpers.httpRequest({ method:'GET', url:`https://gitlab.com/api/v4/projects/${enc}/merge_requests/${mr.iid}/pipelines`, headers:glHeaders });
      pipelines = Array.isArray(pd) ? pd : [];
    } catch(e) {}

    const otherApprovers  = approvers.filter(a => a.user?.id !== mr.author?.id);
    const branchOk        = branchValidPattern.test(mr.source_branch||'') || branchExceptions.test(mr.source_branch||'');
    const hasPipeline     = pipelines.length > 0;
    const pipelineSuccess = pipelines.some(p => p.status === 'success');

    // Pipeline verificada apenas no Backend (único repo com CI configurado)
    const isBackend = repo.slug === 'the-devs6675810/back-end-tecsus';
    const violations = [];
    if (!otherApprovers.length) violations.push('Sem aprovador diferente do autor');
    if (!branchOk)               violations.push(`Branch de origem inválida: \`${mr.source_branch}\``);
    if (isBackend && !hasPipeline)          violations.push('Nenhuma pipeline executada');
    else if (isBackend && !pipelineSuccess) violations.push('Pipeline não passou (status ≠ success)');
    // Descrição MR não obrigatória neste projeto — removido

    mrTotal++;
    if (!violations.length) mrOk++;
    mrResults.push({ repo:repo.name, mrId:mr.iid, title:mr.title, url:mr.web_url, author:mr.author?.name, branch:mr.source_branch, conforme:!violations.length, violations });
  }
}
const mrPct = mrTotal > 0 ? Math.round((mrOk/mrTotal)*100) : 100;
const mrNCs = mrResults.filter(r => !r.conforme);

// ═══════════════════════════════════════════════════════════════════
//  STEP 3 — COMMITS (últimos 30 dias, main + develop + features)
// ═══════════════════════════════════════════════════════════════════
let commitTotal = 0, commitOk = 0;
const commitNCs      = [];
const directMainNCs  = [];
const globalSeenSHAs = new Set(); // de-duplicação: cada SHA conta uma vez globalmente

for (const repo of repos) {
  const enc = encodeURIComponent(repo.slug);
  const isMainRepo = repo.slug === MAIN_REPO_SLUG;

  const branches = await glGet(`https://gitlab.com/api/v4/projects/${enc}/repository/branches`);
  const branchNames = branches.map(b => b.name);
  const mainBranches    = branchNames.filter(b => ['main','develop','master'].includes(b));
  const featureBranches = branchNames.filter(b => /^(feat|fix|docs|refactor|chore|hotfix|release)[\s\-\/\[]/i.test(b));
  const toAudit = [...new Set([...mainBranches, ...featureBranches])];

  const mergedMRs = isMainRepo ? [] : await glGet(`https://gitlab.com/api/v4/projects/${enc}/merge_requests?state=merged&updated_after=${sprintStart.toISOString()}`);
  const mergedSHAs = new Set();
  for (const mr of mergedMRs) {
    try {
      const mrc = await glGet(`https://gitlab.com/api/v4/projects/${enc}/merge_requests/${mr.iid}/commits`);
      mrc.forEach(c => mergedSHAs.add(c.id));
    } catch(e) {}
  }

  for (const branch of toAudit) {
    const commits = await glGet(`https://gitlab.com/api/v4/projects/${enc}/repository/commits?ref_name=${encodeURIComponent(branch)}&since=${sprintStart.toISOString()}&until=${sprintEnd.toISOString()}`);

    for (const c of commits) {
      const title = (c.title || c.message || '').trim();
      if (mergeCommitPattern.test(title)) continue;
      if (globalSeenSHAs.has(c.id)) continue; // já contabilizado em outra branch
      globalSeenSHAs.add(c.id);

      commitTotal++;
      const isMain    = ['main','master'].includes(branch);
      const isDevelop = branch === 'develop';
      const firstWord = title.split(/[:\s\[]/)[0].toLowerCase();
      const isGeneric = genericWords.test(firstWord);
      const isValid   = commitValidPattern.test(title);

      const viols = [];
      if (!isValid)  viols.push(`Convenção inválida: "${title.substring(0,60)}"`);
      if (isGeneric) viols.push('Mensagem genérica ou sem contexto');

      if (!isMainRepo && (isMain || isDevelop) && !mergedSHAs.has(c.id)) {
        directMainNCs.push({ repo:repo.name, branch, sha:c.short_id, title:title.substring(0,80), author:c.author_name, url:`${repo.url}/-/commit/${c.id}` });
      }

      if (!viols.length) commitOk++;
      else commitNCs.push({ repo:repo.name, branch, sha:c.short_id, title:title.substring(0,80), author:c.author_name, url:`${repo.url}/-/commit/${c.id}`, viols });
    }
  }
}
const commitPct = commitTotal > 0 ? Math.round((commitOk/commitTotal)*100) : 100;

// ═══════════════════════════════════════════════════════════════════
//  STEP 4 — BRANCHES (stale após 30 dias, ReleaseSprint* = exceção)
// ═══════════════════════════════════════════════════════════════════
const branchNCs = [];
let branchTotal = 0, branchOk = 0;
const staleCutoff = new Date(now - STALE_DAYS * 24 * 60 * 60 * 1000);

for (const repo of repos) {
  const enc      = encodeURIComponent(repo.slug);
  const branches = await glGet(`https://gitlab.com/api/v4/projects/${enc}/repository/branches`);

  for (const branch of branches) {
    const name = branch.name;
    if (branchExceptions.test(name)) continue; // main, develop, master, ReleaseSprint*

    branchTotal++;
    const nameOk     = branchValidPattern.test(name);
    const lastCommit = new Date(branch.commit?.committed_date || 0);
    const isStale    = lastCommit < staleCutoff;
    const daysSince  = Math.floor((now - lastCommit) / (1000*60*60*24));

    const viols = [];
    if (!nameOk)  viols.push(`Nome fora do padrão feat/fix/docs[ID]: \`${name}\``);
    if (isStale)  viols.push(`Branch parada há ${daysSince} dias (limite: ${STALE_DAYS} dias)`);

    if (!viols.length) branchOk++;
    else branchNCs.push({ repo:repo.name, name, url:`${repo.url}/-/tree/${encodeURIComponent(name)}`, viols, daysSince });
  }
}
const branchPct = branchTotal > 0 ? Math.round((branchOk/branchTotal)*100) : 100;

// ═══════════════════════════════════════════════════════════════════
//  STEP 5 — DOCUMENTAÇÃO
//  NC apenas após 30 dias sem atualização; antes disso: warning informativo
// ═══════════════════════════════════════════════════════════════════
const docResults = [];
const docWarnings = []; // informativo, sem penalizar score
let docTotal = 0, docOk = 0;
const docStaleCutoff = new Date(now - DOC_WARN_DAYS * 24 * 60 * 60 * 1000);

for (const repo of repos) {
  const enc = encodeURIComponent(repo.slug);

  // Buscar commits dos últimos 30 dias em main E develop
  let allSprintCommits = [];
  for (const br of ['main', 'develop']) {
    const commits = await glGet(
      `https://gitlab.com/api/v4/projects/${enc}/repository/commits?ref_name=${encodeURIComponent(br)}&since=${sprintStart.toISOString()}&until=${sprintEnd.toISOString()}`
    );
    allSprintCommits = [...allSprintCommits, ...commits.filter(c => !mergeCommitPattern.test(c.title||''))];
  }

  // Buscar último commit de docs/readme em qualquer branch recente
  // Não usa filtro de path (falha na API) — usa título do commit
  // Pega os 50 commits mais recentes de main e develop sem filtro de data
  let lastDocCommit    = null;
  let lastReadmeCommit = null;
  for (const br of ['main', 'develop']) {
    try {
      const recent = await this.helpers.httpRequest({
        method: 'GET',
        url: `https://gitlab.com/api/v4/projects/${enc}/repository/commits?ref_name=${encodeURIComponent(br)}&per_page=50`,
        headers: glHeaders,
      });
      if (!Array.isArray(recent)) continue;
      let fallbackDate = null;
      for (const c of recent) {
        const t = (c.title || '').toLowerCase();
        // Usar committed_date com fallback para created_at
        const commitDate = c.committed_date || c.authored_date || c.created_at;
        if (!commitDate) continue;
        const d = new Date(commitDate);
        if (isNaN(d.getTime())) continue;
        // Captura o commit mais recente de qualquer tipo como fallback
        if (!fallbackDate) fallbackDate = d;
        if (!lastDocCommit && (t.startsWith('docs:') || t.startsWith('docs[') || t.startsWith('doc:') || t.includes('/docs') || t.includes('documentação'))) {
          lastDocCommit = d;
        }
        if (!lastReadmeCommit && (t.includes('readme') || t.startsWith('docs:') || t.startsWith('docs[') || t.startsWith('doc:'))) {
          lastReadmeCommit = d;
        }
        if (lastDocCommit && lastReadmeCommit) break;
      }
      // Fallback: se não encontrou commit de docs/readme, usa o commit mais recente do repo
      // Isso evita o valor 999 — o repo existe e tem atividade, mas sem prefixo 'docs:'
      if (!lastDocCommit && fallbackDate) lastDocCommit = fallbackDate;
      if (!lastReadmeCommit && fallbackDate) lastReadmeCommit = fallbackDate;
    } catch(e) {}
    if (lastDocCommit && lastReadmeCommit) break;
  }

  const readmeOk = allSprintCommits.some(c => {
    const t = (c.title||'').toLowerCase();
    return t.includes('readme') || t.startsWith('docs:') || t.startsWith('docs[') || t.startsWith('doc:');
  });
  const docsOk = allSprintCommits.some(c => {
    const t = (c.title||'').toLowerCase();
    return t.startsWith('docs:') || t.startsWith('docs[') || t.startsWith('doc:') || t.includes('/docs') || t.includes('documentação') || t.includes('documentacao');
  });

  // Calcular dias desde última atualização
  const daysSinceReadme = lastReadmeCommit ? Math.floor((now-lastReadmeCommit)/(1000*60*60*24)) : 999;
  const daysSinceDocs   = lastDocCommit    ? Math.floor((now-lastDocCommit)/(1000*60*60*24))   : 999;

  // NC apenas se passou de 30 dias sem atualização
  const readmeNC = !readmeOk && daysSinceReadme >= DOC_WARN_DAYS;
  const docsNC   = !docsOk   && daysSinceDocs   >= DOC_WARN_DAYS;

  docTotal += 2;
  if (!readmeNC) docOk++;
  if (!docsNC)   docOk++;

  const result = {
    repo: repo.name, readmeOk: !readmeNC, docsOk: !docsNC,
    daysSinceReadme, daysSinceDocs, commitsThisSpring: allSprintCommits.length, url: repo.url
  };
  docResults.push(result);

  // Warnings informativos (sem penalizar) — entre 0 e 29 dias sem atualização
  if (!readmeOk && daysSinceReadme < DOC_WARN_DAYS)
    docWarnings.push(`[${repo.name}] README sem commit docs há ${daysSinceReadme} dias`);
  if (!docsOk && daysSinceDocs < DOC_WARN_DAYS)
    docWarnings.push(`[${repo.name}] /docs sem commit docs há ${daysSinceDocs} dias`);
}
const docPct = docTotal > 0 ? Math.round((docOk/docTotal)*100) : 100;
const docNCs = docResults.filter(r => !r.readmeOk || !r.docsOk);

// ═══════════════════════════════════════════════════════════════════
//  STEP 6 — TESTES (TC-XX + *.int.spec.ts + *.int.test.ts)
// ═══════════════════════════════════════════════════════════════════
let testTotal = 0, testOk = 0;
const testNCs = [];

for (const repo of repos) {
  if (repo.slug === MAIN_REPO_SLUG) continue;
  const enc = encodeURIComponent(repo.slug);
  let specFiles = [];

  // Estratégia 1: buscar toda a árvore de application-system/src recursivamente
  // A API do GitLab com recursive=true retorna TODOS os arquivos da subárvore
  const basePaths = ['application-system/src', 'src'];
  for (const basePath of basePaths) {
    try {
      const result = await this.helpers.httpRequest({
        method: 'GET',
        url: `https://gitlab.com/api/v4/projects/${enc}/repository/tree?path=${basePath}&recursive=true&per_page=100`,
        headers: glHeaders,
      });
      if (Array.isArray(result) && result.length > 0) {
        // Filtrar apenas arquivos dentro de pastas __tests__
        const found = result.filter(f =>
          f.type === 'blob' &&
          f.path.includes('/__tests__/') &&
          specFilePattern.test(f.name)
        );
        if (found.length > 0) { specFiles = found; break; }
        // Se achou arquivos mas nenhum era spec, sair do loop mesmo assim
        if (result.length > 0) break;
      }
    } catch(e) {}
  }

  // Estratégia 2: fallback — buscar __tests__ diretamente em paths comuns
  if (specFiles.length === 0) {
    for (const testPath of ['__tests__', 'src/__tests__', 'tests', 'test']) {
      try {
        const result = await this.helpers.httpRequest({
          method: 'GET',
          url: `https://gitlab.com/api/v4/projects/${enc}/repository/tree?path=${testPath}&recursive=true&per_page=100`,
          headers: glHeaders,
        });
        if (Array.isArray(result) && result.length > 0) {
          specFiles = result.filter(f => f.type === 'blob' && specFilePattern.test(f.name));
          if (specFiles.length > 0) break;
        }
      } catch(e) {}
    }
  }

  for (const f of specFiles) {
    testTotal++;
    // Aceita: TC-XX-nome.spec.ts | *.int.spec.ts | NomeQualquer.spec.ts
    // NC apenas se nome for genérico (uma só palavra sem contexto, ex: "test.spec.ts")
    const genericTestName = /^(test|spec|index|main|app)\.(spec|test)\.(ts|tsx|js|jsx)$/i;
    if (!genericTestName.test(f.name)) testOk++;
    else testNCs.push({ repo:repo.name, name:f.name, path:f.path, url:`${repo.url}/-/blob/${repo.defaultBranch}/${f.path}` });
  }
}
const testPct = testTotal > 0 ? Math.round((testOk/testTotal)*100) : 100;

// ═══════════════════════════════════════════════════════════════════
//  STEP 7 — JIRA
// ═══════════════════════════════════════════════════════════════════
let jiraSprintName = 'Sprint atual';
let jiraTotal = 0, jiraOk = 0;
const jiraNCs = [];

try {
  const sd = await jiraGet(`https://${JIRA_DOMAIN}/rest/agile/1.0/board/${JIRA_BOARD}/sprint?state=active`);
  if (sd.values?.[0]) jiraSprintName = sd.values[0].name || sd.values[0].displayName || "Sprint atual";
} catch(e) {}

try {
  const jqlDone = encodeURIComponent(`project = SCRUM AND sprint = "${jiraSprintName}" AND status in ("Done", "Concluído", "Concluido") ORDER BY updated DESC`);
  const id  = await jiraGet(`https://${JIRA_DOMAIN}/rest/api/3/search/jql?jql=${jqlDone}&maxResults=100&fields=summary`);
  for (const issue of (id.issues||[])) {
    jiraTotal++;
    let changes = [];
    try {
      const cd = await jiraGet(`https://${JIRA_DOMAIN}/rest/api/3/issue/${issue.key}/changelog`);
      for (const ev of (cd.values||[])) {
        for (const it of (ev.items||[])) {
          if (it.field === 'status') {
            const parsed = JSON.parse(JSON.stringify(it));
            const statusName = parsed.toString || parsed.to || '';
            changes.push(statusName.toLowerCase());
          }
        }
      }
    } catch(e) {}
    const hasProgress = changes.some(s => s.includes('progress')||s.includes('andamento')||s.includes('doing')||s.includes('in progress')||s.includes('em andamento'));
    const hasReview   = changes.some(s => s.includes('review')||s.includes('revis')||s.includes('análise')||s.includes('analise')||s.includes('analysis'));
    const viols = [];
    if (!hasProgress) viols.push('Não passou por "In Progress"');
    if (!hasReview)   viols.push('Não passou por "Review"');
    if (!viols.length) jiraOk++;
    else jiraNCs.push({ key:issue.key, summary:issue.fields.summary, url:`https://${JIRA_DOMAIN}/browse/${issue.key}`, viols });
  }
} catch(e) {}

const jiraPct = jiraTotal > 0 ? Math.round((jiraOk/jiraTotal)*100) : 100;

// ═══════════════════════════════════════════════════════════════════
//  SCORE GLOBAL PONDERADO
// ═══════════════════════════════════════════════════════════════════
const pctGeral = Math.round(mrPct*0.25 + commitPct*0.25 + branchPct*0.15 + docPct*0.15 + testPct*0.10 + jiraPct*0.10);
const severity = (p) => p===100?'CONFORME':p>=80?'ATENÇÃO':p>=60?'ALTO':'CRÍTICO';
const bar      = (p) => { const f=Math.round(p/10); return '█'.repeat(f)+'░'.repeat(10-f)+` ${p}%`; };

// ═══════════════════════════════════════════════════════════════════
//  DISCORD — compacto (máx 1990 chars)
// ═══════════════════════════════════════════════════════════════════
let d = '';
d += `┌─────────────────────────────────────────────┐\n`;
d += `│  📋  AUDITORIA QA FULL SCOPE · DEVOPS       │\n`;
d += `│  Tecsus · 4º Sem · Fatec · The-Devs        │\n`;
d += `└─────────────────────────────────────────────┘\n\n`;
d += `📅  **${periodLabel}**\n`;
d += `🔄  **${jiraSprintName}**  |  📦  **${repos.length} repositórios**\n\n`;
d += `**━━━━  📊 PLACAR DA SPRINT  ━━━━**\n\n`;
