try {
  dailysData = await this.helpers.httpRequest({
    method: 'GET',
    url: `${BOT_URL}/dailys?semana=${semanaAtual}`,
  });
} catch(e) { dailysData = { dailys: [], total: 0, erro: e.message }; }

const totalDailys    = dailysData.total || 0;
const dailyOk        = totalDailys >= 3;
const dailyPct       = Math.min(100, Math.round((totalDailys / 3) * 100));
