if (hasNCs) {
  e += `<h2 style="color:#B71C1C;border-bottom:2px solid #B71C1C;padding-bottom:8px;font-size:15px">⚠️ Não-Conformidades — Lista Completa da Sprint</h2>`;

  if (mrNCs.length) {
    e += `<h3 style="color:#1F3864;font-size:14px">🔀 CI — Merge Requests (${mrNCs.length})</h3><ul style="font-size:13px">`;
    for (const v of mrNCs) e += `<li><b>[${v.repo}] MR !${v.mrId}</b> — ${v.title}<br>👤 ${v.author} · <a href="${v.url}">Ver MR</a><br>${v.violations.map(vi=>`⤷ ${vi}`).join('<br>')}</li>`;
    e += `</ul>`;
  }
  if (commitNCs.length) {
    e += `<h3 style="color:#1F3864;font-size:14px">📝 CI — Commits (${commitNCs.length})</h3>`;
    e += `<p style="font-size:12px;color:#666;margin:0 0 8px">Padrão: <code>tipo[ID]: descrição</code> ou <code>tipo[ID,ID]: desc</code> ou <code>docs: desc</code></p>`;
    e += `<ul style="font-size:13px">`;
    for (const v of commitNCs) e += `<li><code>${v.sha}</code> [${v.repo}/${v.branch}] — ${v.title}<br>${v.viols.map(vi=>`⤷ ${vi}`).join('<br>')} · <a href="${v.url}">Ver</a></li>`;
    e += `</ul>`;
  }
  if (branchNCs.length) {
    e += `<h3 style="color:#1F3864;font-size:14px">🌿 Branches problemáticas (${branchNCs.length})</h3>`;
    e += `<p style="font-size:12px;color:#666;margin:0 0 8px">Padrão: <code>feat/SCRUM-12-descricao</code> ou <code>feat[75,76]-descricao</code> · ReleaseSprint* são exceção permanente</p>`;
    e += `<ul style="font-size:13px">`;
    for (const v of branchNCs) e += `<li><code>${v.name}</code> [${v.repo}]<br>${v.viols.map(vi=>`⤷ ${vi}`).join('<br>')} · <a href="${v.url}">Ver branch</a></li>`;
    e += `</ul>`;
  }
  if (docNCs.length) {
    e += `<h3 style="color:#1F3864;font-size:14px">📄 Documentação (${docNCs.length} repositórios)</h3><ul style="font-size:13px">`;
    for (const v of docNCs) {
      e += `<li><b>[${v.repo}]</b> — ${v.commitsThisSpring} commits na sprint<br>`;
      if (!v.readmeOk) e += `⤷ README sem commit docs há <b>${v.daysSinceReadme} dias</b> (limite: ${DOC_WARN_DAYS}d)<br>`;
      if (!v.docsOk)   e += `⤷ /docs sem commit docs há <b>${v.daysSinceDocs} dias</b> (limite: ${DOC_WARN_DAYS}d)`;
      e += `</li>`;
    }
    e += `</ul>`;
  }
  if (testNCs.length) {
    e += `<h3 style="color:#1F3864;font-size:14px">🧪 Testes fora do padrão (${testNCs.length})</h3>`;
    e += `<p style="font-size:12px;color:#666;margin:0 0 8px">Padrão: <code>TC-XX-nome.spec.ts</code> ou <code>*.int.spec.ts</code> ou <code>*.int.test.ts</code></p>`;
    e += `<ul style="font-size:13px">`;
    for (const v of testNCs) e += `<li><code>${v.name}</code> [${v.repo}] · <a href="${v.url}">Ver arquivo</a></li>`;
    e += `</ul>`;
  }
  if (jiraNCs.length) {
    e += `<h3 style="color:#1F3864;font-size:14px">📌 Rastreabilidade Jira (${jiraNCs.length})</h3><ul style="font-size:13px">`;
    for (const v of jiraNCs) e += `<li><b><a href="${v.url}">${v.key}</a></b> — ${v.summary}<br>${v.viols.map(vi=>`⤷ ${vi}`).join('<br>')}</li>`;
    e += `</ul>`;
  }
} else {
  e += `<div style="background:#E8F5E9;border-left:4px solid #2E7D32;padding:14px;border-radius:4px"><b style="color:#2E7D32">✅ Nenhuma não-conformidade encontrada nesta sprint!</b></div>`;
}


// ── Daily no Email ────────────────────────────────────────────────────────
e += `<h2 style="color:#1F3864;border-bottom:2px solid #2E5FAC;padding-bottom:8px;font-size:15px;margin-top:20px">📡 Daily Scrum</h2>`;
e += `<table width="100%" cellpadding="9" cellspacing="0" style="border-collapse:collapse;font-size:13px;margin-bottom:16px">`;
e += `<tr style="background:#2E5FAC;color:#fff"><th align="left">Dia</th><th align="center">Status</th><th align="center">Presentes</th><th align="center">Duração</th></tr>`;
const diasEmail = ['Segunda','Terça','Quarta','Quinta','Sexta'];
diasEmail.forEach((dia, idx) => {
  const d2 = (dailysData.dailys || []).find(d3 => d3.diaSemana === dia);
  const bg = idx % 2 === 0 ? '' : ' style="background:#F5F7FA"';
  if (d2) {
    e += `<tr${bg}><td style="padding:9px">${dia}</td><td align="center" style="color:#2E7D32;font-weight:600">✅ Realizada</td><td align="center">${d2.presentes.length}/${d2.totalMembros}</td><td align="center">${d2.duracaoMin}min</td></tr>`;
  } else {
    e += `<tr${bg}><td style="padding:9px">${dia}</td><td align="center" style="color:#B71C1C;font-weight:600">❌ Não realizada</td><td align="center">—</td><td align="center">—</td></tr>`;
  }
});
e += `<tr style="background:#FFF8E1;border-top:2px solid #F57F17"><td style="padding:9px"><b>Total na semana</b></td><td align="center" colspan="3"><b>${totalDailys}/semana</b> ${dailyOk ? '✅ (mínimo atingido)' : '⚠️ (mínimo: 3)'}</td></tr>`;
e += `</table>`;

if (impAbertosLista.length > 0) {
  e += `<h3 style="color:#E65100;font-size:14px">🚧 Impedimentos Abertos (${impAbertosLista.length})</h3><ul style="font-size:13px">`;
  for (const imp of impAbertosLista) {
    e += `<li><b>${imp.dev}</b> — ${imp.descricao}${imp.tarefa ? ` <i>(${imp.tarefa})</i>` : ''}</li>`;
  }
  e += `</ul>`;
} else {
  e += `<div style="background:#E8F5E9;border-left:4px solid #2E7D32;padding:10px 14px;border-radius:4px;margin-bottom:16px"><b style="color:#2E7D32">🎉 Nenhum impedimento aberto no momento.</b></div>`;
}
e += `<div style="background:#1F3864;padding:12px 24px;border-radius:0 0 8px 8px;text-align:center"><p style="color:#B0C4DE;margin:0;font-size:12px">🤖 Auditoria automática via n8n · QA de DevOps · Projeto Tecsus · Sprint-based (30d) · ${repos.length} repositórios</p></div></div>`;

return [{ json: {
  discordMessage: d.substring(0, 1990),
  emailBody: e,
  pctGeral,
  periodLabel,
  jiraSprintName,
  discordUrl: DISCORD_URL,
  sendgridKey: SENDGRID_KEY,
  telegraphUrl: telegraphUrl || null,
} }];

